import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userName = reader.readLine();

        try {
            // Encoding the user input to prevent XSS attacks
            String encodedUserName = ESAPI.encoder().encodeForHTML(userName);
            System.out.println("Hello, " + encodedUserName + "!");
        } catch (EncodingException e) {
            System.err.println("Error encoding user input");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
